class SORTracker {

    private final PriorityQueue<Location> maxHeap;
    private final PriorityQueue<Location> minHeap;
    private int queryCount;

    public SORTracker() {
        maxHeap = new PriorityQueue<>((a, b) -> a.score == b.score ? b.name.compareTo(a.name) : b.score - a.score);
        minHeap = new PriorityQueue<>((a, b) -> a.score == b.score ? a.name.compareTo(b.name) : a.score - b.score);
        queryCount = 0;
    }

    public void add(String name, int score) {
        Location location = new Location(name, score);
        maxHeap.offer(location);
        if (queryCount > 0 && location.compareTo(minHeap.peek()) < 0) {
            minHeap.offer(maxHeap.poll());
        }
    }

    public String get() {
        queryCount++;
        if (minHeap.isEmpty() || maxHeap.peek().compareTo(minHeap.peek()) >= 0) {
            return maxHeap.peek().name;
        } else {
            minHeap.offer(maxHeap.poll());
            return minHeap.poll().name;
        }
    }

    private static class Location implements Comparable<Location> {
        String name;
        int score;

        Location(String name, int score) {
            this.name = name;
            this.score = score;
        }

        @Override
        public int compareTo(Location other) {
            return this.score == other.score ? this.name.compareTo(other.name) : this.score - other.score;
        }
    }
}
